 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { AlertType } from '@kubevirt-utils/components/AlertsCard/utils/types';
 5	import LoadingEmptyState from '@kubevirt-utils/components/LoadingEmptyState/LoadingEmptyState';
 6	import useInfrastructureAlerts from '@kubevirt-utils/hooks/useInfrastructureAlerts/useInfrastructureAlerts';
 7	import { t } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { isEmpty } from '@kubevirt-utils/utils/utils';
 9	import { YellowExclamationTriangleIcon } from '@openshift-console/dynamic-plugin-sdk';
10	import { RedExclamationCircleIcon } from '@openshift-console/dynamic-plugin-sdk/lib/app/components/status/icons';
11	import { Divider, Grid, GridItem, Stack, StackItem } from '@patternfly/react-core';
12	
13	import Conditions from './components/Conditions/Conditions';
14	import HealthPopupChart from './components/HealthPopupChart';
15	import { HealthImpactLevel } from './utils/types';
16	import { ALERTS_BASE_PATH } from './utils/utils';
17	
18	import './KubevirtHealthPopup.scss';
19	
20	const KubevirtHealthPopup: FC = () => {
21	  const { alerts, loaded, numberOfAlerts } = useInfrastructureAlerts();
22	  const descriptionText = t(
23	    'You can host and manage virtualized workloads on the same platform as container-based workloads.',
24	  );
25	
26	  const numCriticalAlerts = alerts?.[HealthImpactLevel.critical]?.length;
27	  const numWarningAlerts = alerts?.[AlertType.warning]?.length;
28	
29	  return (
30	    <>
31	      <Grid className="kv-health-popup">
32	        <GridItem className="kv-health-popup__description" span={12}>
33	          {descriptionText}
34	        </GridItem>
35	        <GridItem span={6}>
36	          <Stack>
37	            <StackItem>
38	              <div className="kv-health-popup__title">{t('Alerts')}</div>
39	            </StackItem>
40	            {!isEmpty(numCriticalAlerts) && (
41	              <StackItem>
42	                <div className="kv-health-popup__alerts-count">
43	                  <RedExclamationCircleIcon className="kv-health-popup__alerts-count--icon" />
44	                  <Link to={`${ALERTS_BASE_PATH}${HealthImpactLevel.critical}`}>
45	                    {numCriticalAlerts} {t('Critical')}
46	                  </Link>
47	                </div>
48	              </StackItem>
49	            )}
50	            {!isEmpty(numWarningAlerts) && (
51	              <StackItem>
52	                <div className="kv-health-popup__alerts-count">
53	                  <YellowExclamationTriangleIcon className="kv-health-popup__alerts-count--icon" />{' '}
54	                  <Link to={`${ALERTS_BASE_PATH}${HealthImpactLevel.warning}`}>
55	                    {numWarningAlerts} {t('Warning')}
56	                  </Link>
57	                </div>
58	              </StackItem>
59	            )}
60	          </Stack>
61	        </GridItem>
62	        <GridItem span={6}>
63	          {loaded ? (
64	            <HealthPopupChart alerts={alerts} numberOfAlerts={numberOfAlerts} />
65	          ) : (
66	            <LoadingEmptyState />
67	          )}
68	        </GridItem>
69	      </Grid>
70	
71	      <Divider className="kv-health-popup__divider" />
72	      <Conditions />
73	    </>
74	  );
75	};
76	
77	export default KubevirtHealthPopup;

